import{_ as e,o as r,c as a,ag as n}from"./chunks/framework.OsDJF_Ea.js";const s="/docs/modules/granular-dense.png",g=JSON.parse('{"title":"Granular Dense","description":"","frontmatter":{},"headers":[],"relativePath":"modules/granular-dense.md","filePath":"modules/granular-dense.md"}'),o={name:"modules/granular-dense.md"};function i(d,t,u,h,l,c){return r(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="granular-dense" tabindex="-1">Granular Dense <a class="header-anchor" href="#granular-dense" aria-label="Permalink to &quot;Granular Dense&quot;">​</a></h1><p><strong>Category:</strong> Granular / Looping</p><p>Dense granular processor running 20 simultaneous grains with stereo spread and cloud panning. Creates thick, immersive textures from any audio source. Feedback routes grain output back into the buffer -- with pitch shift this creates cascading shimmer effects where each repeat shifts further.</p><img src="'+s+'" alt="granular-dense module"><h2 id="inputs" tabindex="-1">Inputs <a class="header-anchor" href="#inputs" aria-label="Permalink to &quot;Inputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>inL</strong> (audio)</td><td>Left audio input.</td></tr><tr><td><strong>inR</strong> (audio)</td><td>Right audio input.</td></tr><tr><td><strong>grain_density</strong></td><td>Grains per second. 15-20 creates a thick cloud.</td></tr><tr><td><strong>position</strong></td><td>Playback position in buffer 0-1. At 0 grains read near the write head (delay-like).</td></tr><tr><td><strong>pitch</strong></td><td>Pitch shift in semitones.</td></tr><tr><td><strong>dry_wet</strong></td><td>Dry/wet blend 0-1.</td></tr><tr><td><strong>feedback</strong></td><td>Grain output fed back into buffer 0-0.95. With pitch shift, each iteration shifts further (shimmer). At pitch=0 with low position, acts like a granular delay.</td></tr><tr><td><strong>freeze</strong></td><td>Gate: 1 = freeze buffer, stop recording.</td></tr><tr><td><strong>stereo_width</strong></td><td>Stereo spread of grains 0-1. Each grain randomly placed in stereo field.</td></tr><tr><td><strong>cloud_pan</strong></td><td>Overall cloud position 0-1. Shifts entire grain cloud left/right.</td></tr></tbody></table><h2 id="outputs" tabindex="-1">Outputs <a class="header-anchor" href="#outputs" aria-label="Permalink to &quot;Outputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>outL</strong> (audio)</td><td>Left granular audio.</td></tr><tr><td><strong>outR</strong> (audio)</td><td>Right granular audio.</td></tr></tbody></table><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><p>Shimmer reverb: pitch=+12 semitones, feedback=0.6, position=0.1, high density. Granular delay: pitch=0, feedback=0.7, position near 0, spread=0. Each feedback iteration re-pitches, so +7 semitones creates rising fifths.</p><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2>',11)])])}const f=e(o,[["render",i]]);export{g as __pageData,f as default};
